class MyCalendarThree {
public:
    MyCalendarThree() {
        events = new vector<pair<int, int>>();
    }

    int book(int startTime, int endTime) {
        events->push_back({startTime, 1});
        events->push_back({endTime, -1});
        events->sort();
        int k = 0, maxK = 0;
        for (auto& event : events) {
            k += event.second;
            maxK = max(maxK, k);
        }
        return maxK;
    }
private:
    vector<pair<int, int>>* events;
};
```
